/**
 * Notification service — handles sending notifications for order lifecycle events.
 *
 * Uses direct service-to-service calls for simplicity and debuggability.
 * OrderService calls notification methods directly when orders are created/updated.
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];

  /**
   * Notify that a new order was created — sends confirmation to user.
   */
  notifyOrderCreated(order: Order, user: User): void {
    this.logger.info(`Sending order confirmation for order ${order.id}`);

    const itemSummary = order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: user.email,
      subject: `Order Confirmation: ${order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${order.total.toFixed(2)}`,
    });
  }

  /**
   * Notify that an order status was updated.
   */
  notifyOrderUpdated(order: Order, previousStatus: string, newStatus: string): void {
    this.logger.info(
      `Sending status update for order ${order.id}: ${previousStatus} -> ${newStatus}`,
    );

    this.sendNotification({
      recipient: order.userId,
      subject: `Order Update: ${order.id}`,
      body: `Your order status has changed from ${previousStatus} to ${newStatus}.`,
    });
  }

